#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Start and stop a Databricks cluster
 *
 * This example demonstrates:
 * - Starting a terminated cluster
 * - Waiting for the cluster to reach RUNNING state
 * - Stopping a running cluster
 * - Monitoring state transitions
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 * - An existing cluster ID (set TEST_DEFAULT_CLUSTER_ID environment variable)
 *
 * Usage:
 *   export TEST_DEFAULT_CLUSTER_ID="your-cluster-id"
 *   npx ts-node examples/workspace/clusters/start-stop-cluster.ts
 */

import {WorkspaceClient, Time, TimeUnits} from "@databricks/sdk-experimental";

async function main() {
    const client = new WorkspaceClient({});

    const clusterId = process.env.TEST_DEFAULT_CLUSTER_ID;

    if (!clusterId) {
        console.error(
            "✗ Error: TEST_DEFAULT_CLUSTER_ID environment variable not set"
        );
        console.error(
            "  Please set it to an existing cluster ID or create a cluster first."
        );
        process.exit(1);
    }

    console.log(`Working with cluster: ${clusterId}\n`);

    try {
        // Get current cluster state
        const cluster = await client.clusters.get({cluster_id: clusterId});
        console.log(`Current state: ${cluster.state}`);

        // If cluster is terminated, start it
        if (cluster.state === "TERMINATED" || cluster.state === "TERMINATING") {
            console.log(`\nStarting cluster ${clusterId}...`);

            const startWaiter = await client.clusters.start({
                cluster_id: clusterId,
            });

            const runningCluster = await startWaiter.wait({
                timeout: new Time(10, TimeUnits.minutes),
                onProgress: async (c) => {
                    console.log(`  Cluster state: ${c.state}`);
                },
            });

            console.log(`✓ Cluster started successfully`);
            console.log(`  Current state: ${runningCluster.state}`);
        } else if (cluster.state === "RUNNING") {
            console.log(`  Cluster is already running`);
        } else {
            console.log(
                `  Cluster is in ${cluster.state} state - waiting for stable state...`
            );
        }

        // Stop the cluster
        console.log(`\nStopping cluster ${clusterId}...`);

        const stopWaiter = await client.clusters.delete({
            cluster_id: clusterId,
        });

        const terminatedCluster = await stopWaiter.wait({
            timeout: new Time(10, TimeUnits.minutes),
            onProgress: async (c) => {
                console.log(`  Cluster state: ${c.state}`);
            },
        });

        console.log(`✓ Cluster stopped successfully`);
        console.log(`  Final state: ${terminatedCluster.state}`);
    } catch (error) {
        console.error(`✗ Error:`, error);
        process.exit(1);
    }
}

main();
